// Procesar datos del webhook y preparar para Mistral OCR
const inputData = $input.all();
const webhookData = inputData[0];

// Extraer metadata si existe
let metadata = {};
if (webhookData.json && webhookData.json.metadata) {
  try {
    metadata = typeof webhookData.json.metadata === 'string' 
      ? JSON.parse(webhookData.json.metadata) 
      : webhookData.json.metadata;
  } catch (e) {
    console.log('Error parsing metadata:', e);
  }
}

// Preparar datos para el nodo Mistral
const output = {
  metadata: metadata,
  file_info: {
    filename: webhookData.binary?.file?.fileName || 'unknown',
    mimeType: webhookData.binary?.file?.mimeType || 'image/png',
    fileSize: webhookData.binary?.file?.fileSize || 0
  },
  processing_timestamp: new Date().toISOString(),
  rgpd_processed: true
};

// Pasar el archivo binario
if (webhookData.binary && webhookData.binary.file) {
  $binary.file = webhookData.binary.file;
}

return output;

// Formatear respuesta del OCR de Mistral
const inputData = $input.all();
const ocrResult = inputData[0];
const preparedData = $node["Prepare Data for OCR"].json;

// Extraer texto del resultado de Mistral
let extractedText = '';
let confidence = 0;
let pages = 1;
let language = 'unknown';

if (ocrResult && ocrResult.json) {
  // Mistral OCR devuelve el texto en diferentes formatos
  if (ocrResult.json.text) {
    extractedText = ocrResult.json.text;
  } else if (ocrResult.json.content) {
    extractedText = ocrResult.json.content;
  } else if (typeof ocrResult.json === 'string') {
    extractedText = ocrResult.json;
  }

  // Extraer metadata adicional si está disponible
  if (ocrResult.json.confidence) {
    confidence = ocrResult.json.confidence;
  }

  if (ocrResult.json.pages) {
    pages = ocrResult.json.pages;
  }
}

// Detectar idioma básico
if (extractedText) {
  const spanishWords = ['el', 'la', 'de', 'que', 'y', 'en', 'un', 'es', 'se', 'no', 'te', 'lo', 'le', 'da', 'su', 'por', 'son', 'con', 'para', 'al', 'del', 'los', 'las', 'una', 'como', 'pero', 'sus', 'han', 'fue', 'ser', 'está', 'todo', 'más', 'muy', 'sin', 'sobre', 'también', 'hasta', 'año', 'años', 'dos', 'puede', 'entre', 'cada', 'hace', 'otro', 'otros', 'nueva', 'nuevo', 'gran', 'tiempo', 'trabajo', 'vida', 'día', 'días', 'parte', 'general', 'caso', 'mismo', 'manera', 'bien', 'donde', 'mientras', 'según', 'estado', 'forma', 'tanto', 'agua', 'lugar', 'hombre', 'mundo', 'casa', 'país', 'grupo', 'empresa', 'gobierno', 'persona', 'personas', 'ciudad', 'nacional', 'social', 'público', 'económico', 'política', 'internacional', 'desarrollo', 'sistema', 'proceso', 'información', 'servicio', 'servicios', 'producto', 'productos', 'mercado', 'precio', 'precios', 'cliente', 'clientes', 'factura', 'número', 'fecha', 'nombre', 'dirección', 'teléfono', 'email', 'euros', 'total', 'subtotal', 'iva', 'descuento'];
  const englishWords = ['the', 'be', 'to', 'of', 'and', 'a', 'in', 'that', 'have', 'i', 'it', 'for', 'not', 'on', 'with', 'he', 'as', 'you', 'do', 'at', 'this', 'but', 'his', 'by', 'from', 'they', 'she', 'or', 'an', 'will', 'my', 'one', 'all', 'would', 'there', 'their', 'what', 'so', 'up', 'out', 'if', 'about', 'who', 'get', 'which', 'go', 'me', 'when', 'make', 'can', 'like', 'time', 'no', 'just', 'him', 'know', 'take', 'people', 'into', 'year', 'your', 'good', 'some', 'could', 'them', 'see', 'other', 'than', 'then', 'now', 'look', 'only', 'come', 'its', 'over', 'think', 'also', 'back', 'after', 'use', 'two', 'how', 'our', 'work', 'first', 'well', 'way', 'even', 'new', 'want', 'because', 'any', 'these', 'give', 'day', 'most', 'us', 'is', 'water', 'long', 'find', 'here', 'thing', 'great', 'man', 'world', 'life', 'still', 'public', 'human', 'get', 'old', 'country', 'hand', 'part', 'child', 'eye', 'woman', 'place', 'work', 'week', 'case', 'point', 'government', 'company', 'number', 'group', 'problem', 'fact', 'invoice', 'date', 'name', 'address', 'phone', 'email', 'total', 'subtotal', 'tax', 'discount'];

  const textLower = extractedText.toLowerCase();
  let spanishCount = 0;
  let englishCount = 0;

  spanishWords.forEach(word => {
    if (textLower.includes(word)) spanishCount++;
  });

  englishWords.forEach(word => {
    if (textLower.includes(word)) englishCount++;
  });

  language = spanishCount > englishCount ? 'es' : (englishCount > spanishCount ? 'en' : 'unknown');
}

// Estadísticas del texto
const textStats = {
  characters: extractedText.length,
  words: extractedText.split(/\s+/).filter(word => word.length > 0).length,
  lines: extractedText.split('\n').length,
  language: language
};

// Formatear respuesta final
const response = {
  success: true,
  message: 'OCR procesado exitosamente con Mistral AI',
  ocr_result: {
    extracted_text: extractedText,
    confidence: confidence,
    pages: pages,
    language: language,
    text_stats: textStats
  },
  processing_info: {
    timestamp: new Date().toISOString(),
    model_used: 'mistral-ocr-latest',
    rgpd_compliant: true,
    file_info: preparedData.file_info || {},
    metadata: preparedData.metadata || {}
  },
  raw_mistral_response: ocrResult.json
};

return response;

// Manejar errores del OCR
const error = $input.all()[0];

const errorResponse = {
  success: false,
  message: 'Error en el procesamiento OCR con Mistral AI',
  error: {
    type: 'OCR_ERROR',
    details: error.error?.message || error.message || 'Error desconocido',
    timestamp: new Date().toISOString()
  },
  processing_info: {
    model_used: 'mistral-ocr-latest',
    rgpd_compliant: true,
    failed_at: 'mistral_ocr_processing'
  }
};

return errorResponse;
